export const storageService = {
  async uploadUrl(filename: string) {
    const tenantId = tenantContext.requireTenant();
    const key = `tenants/${tenantId}/${crypto.randomUUID()}/${filename}`;
    return s3.getSignedUrl('putObject', { Bucket: 'uploads', Key: key, Expires: 300 });
  },
  async downloadUrl(key: string) {
    const tenantId = tenantContext.requireTenant();
    if (!key.startsWith(`tenants/${tenantId}/`)) throw new ForbiddenError();
    return s3.getSignedUrl('getObject', { Bucket: 'uploads', Key: key, Expires: 600 });
  }
};

// server/routes/webhookTest.ts
import { Router } from 'express';
import { createHmac } from 'crypto';
export const webhookTestRouter = Router();
webhookTestRouter.post('/webhooks/:id/test', async (req, res) => {
  const wh = await WebhookModel.findById(req.params.id);
  if (!wh) return res.status(404).end();
  const body = JSON.stringify({ event: 'webhook.test', data: { ok: true }, timestamp: Date.now() });
  const sig = createHmac('sha256', wh.signingSecret).update(body).digest('hex');
  try {
    const r = await fetch(wh.url, { method: 'POST', headers: { 'content-type': 'application/json', 'x-signature': sig }, body, signal: AbortSignal.timeout(5000) });
    res.json({ ok: r.ok, status: r.status, body: await r.text().catch(() => null) });
  } catch (e: any) { res.json({ ok: false, error: e.message }); }
});

