export const transferService = {
  async initiate(workspaceId: string, targetUserId: string) {
    await TransferRequestModel.create({ workspaceId, fromUserId: currentUser(), toUserId: targetUserId, expiresAt: new Date(Date.now() + 7*86400000) });
    await emailJob.send({ to: targetEmail, template: 'transfer_request', ... });
  },
  async accept(transferId: string) {
    const t = await TransferRequestModel.findById(transferId);
    if (!t || t.toUserId !== currentUser() || t.expiresAt < new Date()) throw new ConflictError();
    await WorkspaceModel.updateOne({ _id: t.workspaceId }, { ownerId: currentUser() });
    t.acceptedAt = new Date(); await t.save();
    await audit('workspace:ownership_transferred', { subjectId: t.workspaceId });
  }
};

