// client/components/InteractiveLegend.tsx
import { useState } from 'react';
import { LineChart, Line, Legend, ResponsiveContainer } from 'recharts';
export function InteractiveChart({ data, keys }: any) {
  const [hidden, setHidden] = useState<Set<string>>(new Set());
  return (
    <ResponsiveContainer height={300}><LineChart data={data}>
      {keys.map((k: string, i: number) => <Line key={k} dataKey={k} hide={hidden.has(k)} stroke={OKABE_ITO[i]} />)}
      <Legend content={({ payload }) => <ul className="flex gap-2">{payload?.map((p: any) => <li key={p.dataKey}><button onClick={() => setHidden(prev => { const n = new Set(prev); n.has(p.dataKey) ? n.delete(p.dataKey) : n.add(p.dataKey); return n; })} aria-pressed={!hidden.has(p.dataKey)}>{p.value}</button></li>)}</ul>} />
    </LineChart></ResponsiveContainer>
  );
}

